import time
import threading
from dataclasses import dataclass, field
from enum import Enum
from typing import Callable, Any

class CircuitState(Enum):
    CLOSED = "closed"
    OPEN = "open"
    HALF_OPEN = "half_open"

@dataclass
class CircuitBreakerConfig:
    failure_threshold: int = 5       # failures to trip OPEN
    success_threshold: int = 2       # successes to close from HALF_OPEN
    recovery_timeout_s: float = 30.0 # seconds before attempting HALF_OPEN
    half_open_max_calls: int = 3     # concurrent probes in HALF_OPEN

class CircuitBreaker:
    def __init__(self, name: str, config: CircuitBreakerConfig):
        self.name = name
        self.cfg = config
        self._state = CircuitState.CLOSED
        self._failures = 0
        self._successes = 0
        self._last_failure_time = 0.0
        self._lock = threading.Lock()

    @property
    def state(self) -> CircuitState:
        if self._state == CircuitState.OPEN:
            if time.monotonic() - self._last_failure_time > self.cfg.recovery_timeout_s:
                with self._lock:
                    self._state = CircuitState.HALF_OPEN
                    self._successes = 0
        return self._state

    def call(self, fn: Callable, *args, **kwargs) -> Any:
        s = self.state
        if s == CircuitState.OPEN:
            raise RuntimeError(f"Circuit {self.name} OPEN — fast-fail")

        try:
            result = fn(*args, **kwargs)
            self._on_success()
            return result
        except Exception as exc:
            self._on_failure()
            raise

    def _on_success(self):
        with self._lock:
            self._failures = 0
            if self._state == CircuitState.HALF_OPEN:
                self._successes += 1
                if self._successes >= self.cfg.success_threshold:
                    self._state = CircuitState.CLOSED

    def _on_failure(self):
        with self._lock:
            self._failures += 1
            self._last_failure_time = time.monotonic()
            if self._failures >= self.cfg.failure_threshold:
                self._state = CircuitState.OPEN

from dataclasses import dataclass

@dataclass
class BurnRateAlert:
    slo_target: float           # e.g. 0.999
    window_short_m: int = 5     # fast window (minutes)
    window_long_m: int = 60     # slow window (minutes)
    burn_rate_threshold: float = 14.4  # 5% budget in 1h = 14.4x

    @property
    def error_budget(self) -> float:
        return 1.0 - self.slo_target

    def should_page(
        self,
        error_rate_short: float,  # error rate over fast window
        error_rate_long: float,   # error rate over slow window
    ) -> bool:
        # Requires BOTH windows to fire — reduces false positives
        burn_short = error_rate_short / self.error_budget
        burn_long = error_rate_long / self.error_budget
        return burn_short > self.burn_rate_threshold and burn_long > self.burn_rate_threshold

    def time_to_exhaustion_h(self, current_error_rate: float) -> float:
        # How long until 100% of monthly budget consumed at this rate?
        monthly_budget_h = (self.error_budget * 30 * 24)
        if current_error_rate <= 0:
            return float("inf")
        return monthly_budget_h / (current_error_rate / self.error_budget)

# Usage
alert = BurnRateAlert(slo_target=0.999)
if alert.should_page(error_rate_short=0.05, error_rate_long=0.03):
    print("PAGE: error budget burning at 14.4x — 100% exhausted in ~2h")
tte = alert.time_to_exhaustion_h(current_error_rate=0.01)
print(f"Budget exhaustion in {tte:.1f}h at current rate")

from dataclasses import dataclass
from typing import Optional
import math

@dataclass
class AvailabilityNFR:
    service_tier: str
    slo_target: float           # e.g. 0.999 for 99.9%
    rto_minutes: int            # Recovery Time Objective
    rpo_minutes: int            # Recovery Point Objective
    measurement_window_days: int = 30
    topology_required: str = "single-region-ha"

    @property
    def error_budget_minutes(self) -> float:
        return (1.0 - self.slo_target) * self.measurement_window_days * 24 * 60

    @property
    def nines(self) -> int:
        if self.slo_target >= 1.0:
            return 999
        return math.floor(-math.log10(1 - self.slo_target))

    def validate(self) -> list[str]:
        errors = []
        if self.slo_target < 0 or self.slo_target >= 1.0:
            errors.append(f"SLO target {self.slo_target} out of range [0, 1)")
        if self.rto_minutes < 0:
            errors.append("RTO must be non-negative")
        if self.rpo_minutes < 0:
            errors.append("RPO must be non-negative")
        if self.slo_target >= 0.999 and self.topology_required == "single-region":
            errors.append("99.9%+ SLO requires multi-region topology")
        if self.rto_minutes < 5 and self.topology_required != "active-active":
            errors.append("RTO < 5 min requires active-active topology")
        return errors

# Define NFRs in architecture spec
nfrs = {
    "inference_endpoint": AvailabilityNFR(
        service_tier="revenue-critical",
        slo_target=0.999,
        rto_minutes=5,
        rpo_minutes=0,
        topology_required="active-passive-multi-region",
    ),
    "vector_store": AvailabilityNFR(
        service_tier="revenue-critical",
        slo_target=0.999,
        rto_minutes=5,
        rpo_minutes=0,
        topology_required="multi-az",
    ),
}

for component, nfr in nfrs.items():
    errors = nfr.validate()
    if errors:
        raise ValueError(f"{component} NFR invalid: {errors}")
    print(f"{component}: {nfr.nines} nines | budget={nfr.error_budget_minutes:.0f}min/month")

