from enum import Enum
from typing import Optional

class DegradationLevel(Enum):
    FULL = "full"           # normal operation
    CACHED = "cached"       # serve stale cached completions
    SIMPLIFIED = "simplified"  # route to smaller / cheaper model
    QUEUED = "queued"       # return 202 + job ID, fulfill async
    UNAVAILABLE = "unavailable"  # return 503 with retry-after

@dataclass
class DegradationPolicy:
    provider_error_rate_threshold: float = 0.05  # trip at 5% errors
    cache_max_staleness_s: int = 3600           # 1h stale cache ok
    fallback_model_id: Optional[str] = None     # smaller model endpoint
    queue_max_depth: int = 500                   # 503 when queue full

    def select_level(
        self,
        provider_error_rate: float,
        cache_hit_available: bool,
        queue_depth: int,
    ) -> DegradationLevel:
        if provider_error_rate < self.provider_error_rate_threshold:
            return DegradationLevel.FULL
        if cache_hit_available:
            return DegradationLevel.CACHED
        if self.fallback_model_id:
            return DegradationLevel.SIMPLIFIED
        if queue_depth < self.queue_max_depth:
            return DegradationLevel.QUEUED
        return DegradationLevel.UNAVAILABLE
